# red_team/report.py
def generate_red_team_report(run_result: dict) -> str:
    lines = [
        "# Red-Team Run Report",
        f"Total scenarios: {run_result['total']}",
        f"Defenses held: {run_result['held']}",
        f"Breaches: {run_result['breached']} ({run_result['breach_rate']:.0%})",
        f"Critical breaches: {run_result['critical_breaches']}",
        f"Release blocking: {'YES' if run_result['release_blocking'] else 'No'}",
        "",
    ]
    if run_result["breached"] > 0:
        lines += ["## Breaches", ""]
        for r in run_result["results"]:
            if r.failure_detected:
                lines += [
                    f"### [{r.severity.upper()}] {r.scenario_id}",
                    f"**Defense verdict:** BREACHED",
                    f"**Reason:** {r.judge_reason}",
                    f"**Response excerpt:** {r.response[:300]}...",
                    "",
                ]
    return "\n".join(lines)
